SELECT mean_temperature_f
FROM weather_measurements
WHERE date_time LIKE '2023-10-01%';

SELECT MAX(max_temperature_f) AS max_temperature
FROM weather_measurements
WHERE station_id = 0;

SELECT measurement_id, AVG(mean_temperature_f) AS avg_mean_temperature
FROM weather_measurements
GROUP BY measurement_id;

SELECT mean_temperature_f, mean_humidity
FROM weather_measurements
WHERE measurement_id = 0;
